#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=40010,Mod=19260817,NQ=1e5+10;int n,Q,a[N],head[N],des[N<<1],nxt[N<<1],cgt,cct;
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
int val[Mod],idx[Mod];inline int qry(const int &x)
{
	int hsh=x%Mod;while(idx[hsh]){if(idx[hsh]==x)return val[hsh];++hsh;}
	idx[hsh]=x;return val[hsh]=++cct;
}
int eul[N<<1],siz[N],mxs[N],fa[N],dep[N],cdt,top[N],ql[N],qr[N],lca[NQ],Ans,ans[NQ],cnt[N];bool vis[N];
struct Query{int l,r,idx;inline bool operator<(const Query &Q)const{return (l>>9)==(Q.l>>9)?(((l>>9)&1)?r>Q.r:r<Q.r):l<Q.l;}}t[NQ];
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];siz[v]>mx?mx=siz[v],mxs[u]=v:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	top[eul[++cdt]=u]=tp;ql[u]=cdt;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);eul[++cdt]=u;qr[u]=cdt;
}
inline int LCA(int u,int v){while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];return dep[u]<dep[v]?u:v;}
inline void ins(const int &x){Ans+=!(cnt[x]++);} inline void del(const int &x){Ans-=!(--cnt[x]);}
inline void opr(const int &x){vis[x]?(del(a[x]),vis[x]=false):(ins(a[x]),vis[x]=true);}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=qry(read());rep(2,n,i)ins(read(),read()); 
//	rep(1,n,i)printf("%d ",a[i]);
	dfs1();dfs2();rep(1,Q,i)
	{
		int u=read(),v=read(),Lca=LCA(u,v);if(ql[u]>ql[v]){int tmp=u;u=v;v=tmp;}
		if(Lca==u){t[i].l=ql[u];t[i].r=ql[v];} else {t[i].l=qr[u];t[i].r=ql[v];lca[i]=a[Lca];} t[i].idx=i;
	}
	std::sort(t+1,t+Q+1); int L=t[1].l,R=t[1].l-1;
	rep(1,Q,i)
	{
		while(R<t[i].r)opr(eul[++R]);while(L>t[i].l)opr(eul[--L]);
		while(R>t[i].r)opr(eul[R--]);while(L<t[i].l)opr(eul[L++]);
		if(lca[t[i].idx]){ins(lca[t[i].idx]);ans[t[i].idx]=Ans;del(lca[t[i].idx]);} else ans[t[i].idx]=Ans;
	}
	rep(1,Q,i)print(ans[i]),putchar('\n');return 0;
}
